import { io } from 'socket.io-client';

// WebSocket server URL
const SOCKET_URL = process.env.REACT_APP_SOCKET_URL || 'http://localhost:3001';

class SocketService {
  constructor() {
    this.socket = null;
    this.connected = false;
  }

  connect(walletAddress) {
    if (this.socket && this.connected) {
      console.log('Socket already connected');
      return;
    }

    console.log('Connecting to WebSocket server...');
    
    this.socket = io(SOCKET_URL, {
      transports: ['websocket', 'polling'],
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionAttempts: 5
    });

    this.socket.on('connect', () => {
      console.log('✅ Connected to WebSocket server');
      this.connected = true;
      
      // Join with wallet address
      if (walletAddress) {
        this.socket.emit('join', walletAddress);
      }
    });

    this.socket.on('joined', (data) => {
      console.log('Joined as:', data.walletAddress);
    });

    this.socket.on('disconnect', () => {
      console.log('❌ Disconnected from WebSocket server');
      this.connected = false;
    });

    this.socket.on('connect_error', (error) => {
      console.error('Connection error:', error.message);
    });

    return this.socket;
  }

  disconnect() {
    if (this.socket) {
      this.socket.disconnect();
      this.socket = null;
      this.connected = false;
      console.log('Disconnected from WebSocket server');
    }
  }

  joinChat(chatId, participants) {
    if (this.socket && this.connected) {
      this.socket.emit('join-chat', { chatId, participants });
    }
  }

  sendMessage(chatId, message) {
    if (this.socket && this.connected) {
      this.socket.emit('private-message', { chatId, message });
    }
  }

  deleteMessage(chatId, messageId, deleteType) {
    if (this.socket && this.connected) {
      this.socket.emit('delete-message', { chatId, messageId, deleteType });
    }
  }

  onNewMessage(callback) {
    if (this.socket) {
      this.socket.on('new-message', callback);
    }
  }

  onChatHistory(callback) {
    if (this.socket) {
      this.socket.on('chat-history', callback);
    }
  }

  onMessageDeleted(callback) {
    if (this.socket) {
      this.socket.on('message-deleted', callback);
    }
  }

  onChatNotification(callback) {
    if (this.socket) {
      this.socket.on('chat-notification', callback);
    }
  }

  sendTyping(chatId, walletAddress) {
    if (this.socket && this.connected) {
      this.socket.emit('typing', { chatId, walletAddress });
    }
  }

  sendStopTyping(chatId, walletAddress) {
    if (this.socket && this.connected) {
      this.socket.emit('stop-typing', { chatId, walletAddress });
    }
  }

  onUserTyping(callback) {
    if (this.socket) {
      this.socket.on('user-typing', callback);
    }
  }

  onUserStopTyping(callback) {
    if (this.socket) {
      this.socket.on('user-stop-typing', callback);
    }
  }

  isConnected() {
    return this.connected;
  }

  removeAllListeners() {
    if (this.socket) {
      this.socket.removeAllListeners();
    }
  }
}

// Create singleton instance
const socketService = new SocketService();

export default socketService;
